INSERT INTO `cims_bank_account_status` (`id`, `bank_account_status`, `bank_link_id`, `bank_name`, `is_active`, `tooltip`, `created_at`, `updated_at`) VALUES
(1, 'Active / Open', 3, 'First National Bank', 1, 'The account is ready for normal use: deposits, withdrawals, transfers, debit orders, etc.\r\n\r\nConsidered the standard state when an account is in regular transaction use.\r\n\r\nTerminology used:\r\n* “Active” or “Open” — refers to accounts which are currently operational and can transact (most banks report “open” in verification)', NULL, NULL),
(2, 'Inactive', 3, 'First National Bank', 1, 'No transactions have been performed for a defined period.\r\n\r\nOften a precursor to dormancy if still unused.\r\n\r\nExamples / Notes:\r\n\r\nFNB: An account with no transactions can be deemed inactive, and if inactivity continues it can move to dormant.\r\n\r\nSome banks may label no transaction yet accounts as “inactive” until first use.', NULL, NULL),
(3, 'Dormant', 3, 'First National Bank', 1, 'A specific dormancy stage which means no client-initiated activity for a while.\r\n\r\nBanks will often freeze the account for outgoing transactions while allowing some limited credits or reactivation steps.\r\n\r\nGeneral rules you’ll see across banks:\r\n\r\nDormancy usually arises after a period of inactivity (often 6–24+ months, depending on bank policy & product).\r\n\r\nFees may still be charged while an account is dormant.\r\n\r\nLater it can proceed to closure if still unused.', NULL, NULL),
(4, 'Closed', 3, 'First National Bank', 1, 'Account has been formally terminated:\r\n\r\nBy the account holder\r\n\r\nBy the bank (e.g., inactivity > dormancy period, compliance reasons)\r\n\r\nOnce closed, the account number may eventually be re-used by the bank, and balance handling follows regulatory unclaimed funds policies.', NULL, NULL),
(5, 'Frozen / Restricted / Suspended', 3, 'First National Bank', 1, 'Some banks will restrict activity (freeze outgoing transactions) in specific compliance or risk scenarios:\r\n\r\nOutdated Know Your Customer (KYC) info\r\n\r\nSuspected fraud\r\n\r\nRegulatory requirements\r\n\r\nExample:\r\nFNB may freeze an account if KYC documents aren’t provided, even if the account is not technically considered “dormant”.', NULL, NULL),
(6, 'Active / Open', 1, 'ABSA Bank', 1, 'The account is ready for normal use: deposits, withdrawals, transfers, debit orders, etc.\r\n\r\nConsidered the standard state when an account is in regular transaction use.\r\n\r\nTerminology used:\r\n* “Active” or “Open” — refers to accounts which are currently operational and can transact (most banks report “open” in verification)', NULL, NULL),
(7, 'Active / Open', 2, 'Capitec Bank ', 1, 'The account is ready for normal use: deposits, withdrawals, transfers, debit orders, etc.\r\n\r\nConsidered the standard state when an account is in regular transaction use.\r\n\r\nTerminology used:\r\n* “Active” or “Open” — refers to accounts which are currently operational and can transact (most banks report “open” in verification)', NULL, NULL);

