(1, 'Easy Account', 3, 'First National Bank', 0, NULL, NULL, NULL),
(2, 'Private Client', 3, 'First National Bank', 0, NULL, NULL, NULL),
(3, 'Platinum Account', 3, 'First National Bank', 0, NULL, NULL, NULL),
(4, 'Hair Cut Account', 4, 'Investec', 1, NULL, NULL, NULL),
(5, 'Old School Account', 2, 'Capitec', 1, NULL, NULL, NULL),
(13, 'First Business Zero Account', 3, 'First National Bank', 1, 'Designed for new entrepreneurs & sole proprietors with minimal fees.\r\n\r\nZero monthly account fee.\r\n\r\nFree or low-cost basic transactions (card swipes, deposits).\r\n\r\nUsually for smaller turnover businesses or startups.', NULL, NULL),
(14, 'Gold Business Account', 3, 'First National Bank', 1, 'A bundle account with fixed monthly fee (e.g., R99).\r\n\r\nIncludes free monthly transactions up to a set number.\r\n\r\nEarn eBucks Rewards on qualifying transactions.\r\n\r\nIdeal for small to mid-sized businesses that want predictable fees.', NULL, NULL),
(15, 'Platinum Business Account', 3, 'First National Bank', 1, 'A higher-tier business account with enhanced limits and features.\r\n\r\nLikely includes greater transaction allowances and premium benefits compared with Gold.\r\n\r\nDesigned for growing SMEs who do more transactions monthly.', NULL, NULL),
(16, 'Enterprise or Corporate Account', 3, 'First National Bank', 1, 'These are advanced / larger turnover accounts tailored for established businesses.\r\n\r\nMay include working capital solutions, overdrafts, specialised cash-flow products, and structured finance facilities.\r\n\r\nOften combined with relationship management services and lending products.', NULL, NULL);

