--
-- Table structure for table `client_master`
--

CREATE TABLE `client_master` (
  `client_id` bigint(20) UNSIGNED NOT NULL,
  `company_name` varchar(255) NOT NULL,
  `company_reg_number` varchar(50) DEFAULT NULL,
  `company_type` varchar(50) DEFAULT NULL,
  `company_reg_date` date DEFAULT NULL,
  `financial_year_end` varchar(20) DEFAULT NULL,
  `trading_name` varchar(255) DEFAULT NULL,
  `client_code` varchar(50) NOT NULL,
  `bizportal_number` varchar(100) DEFAULT NULL,
  `month_no` varchar(10) DEFAULT NULL,
  `number_of_directors` int(11) DEFAULT NULL,
  `number_of_shares` int(11) DEFAULT NULL,
  `share_type_name` varchar(255) DEFAULT NULL,
  `tax_number` varchar(50) DEFAULT NULL,
  `tax_reg_date` date DEFAULT NULL,
  `cipc_annual_returns` varchar(20) DEFAULT NULL,
  `paye_number` varchar(50) DEFAULT NULL,
  `sdl_number` varchar(50) DEFAULT NULL,
  `uif_number` varchar(50) DEFAULT NULL,
  `dept_labour_number` varchar(50) DEFAULT NULL,
  `wca_coida_number` varchar(50) DEFAULT NULL,
  `payroll_liability_date` date DEFAULT NULL,
  `vat_number` varchar(50) DEFAULT NULL,
  `vat_reg_date` date DEFAULT NULL,
  `vat_return_cycle` varchar(20) DEFAULT NULL,
  `vat_cycle_name` varchar(255) DEFAULT NULL,
  `vat_cycle_id` int(11) DEFAULT NULL,
  `vat_effect_from` date DEFAULT NULL,
  `phone_business` varchar(20) DEFAULT NULL,
  `phone_mobile` varchar(20) DEFAULT NULL,
  `direct` varchar(20) DEFAULT NULL,
  `phone_whatsapp` varchar(20) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `email_admin` varchar(100) DEFAULT NULL,
  `website` varchar(150) DEFAULT NULL,
  `sars_rep_first_name` varchar(100) DEFAULT NULL,
  `sars_rep_middle_name` varchar(100) DEFAULT NULL,
  `sars_rep_surname` varchar(100) DEFAULT NULL,
  `sars_rep_initial` varchar(10) DEFAULT NULL,
  `sars_rep_title` varchar(20) DEFAULT NULL,
  `sars_rep_gender` varchar(10) DEFAULT NULL,
  `sars_rep_id_number` varchar(20) DEFAULT NULL,
  `sars_rep_id_type` varchar(30) DEFAULT NULL,
  `sars_rep_id_issue_date` date DEFAULT NULL,
  `sars_rep_tax_number` varchar(20) DEFAULT NULL,
  `sars_rep_position` varchar(100) DEFAULT NULL,
  `sars_rep_date_registered` date DEFAULT NULL,
  `sars_login` varchar(100) DEFAULT NULL,
  `sars_password` varchar(255) DEFAULT NULL,
  `sars_otp_mobile` varchar(20) DEFAULT NULL,
  `sars_otp_email` varchar(100) DEFAULT NULL,
  `bank_account_holder` varchar(150) DEFAULT NULL,
  `bank_account_number` varchar(30) DEFAULT NULL,
  `bank_account_type` varchar(30) DEFAULT NULL,
  `bank_name` varchar(100) DEFAULT NULL,
  `bank_branch_code` varchar(20) DEFAULT NULL,
  `director_first_name` varchar(100) DEFAULT NULL,
  `director_middle_name` varchar(100) DEFAULT NULL,
  `director_surname` varchar(100) DEFAULT NULL,
  `director_initial` varchar(10) DEFAULT NULL,
  `director_title` varchar(20) DEFAULT NULL,
  `director_gender` varchar(10) DEFAULT NULL,
  `director_id_number` varchar(20) DEFAULT NULL,
  `director_id_type` varchar(30) DEFAULT NULL,
  `director_id_issue_date` date DEFAULT NULL,
  `director_marital_status` varchar(30) DEFAULT NULL,
  `director_marriage_type` varchar(30) DEFAULT NULL,
  `director_marriage_date` date DEFAULT NULL,
  `partner_first_name` varchar(100) DEFAULT NULL,
  `partner_middle_name` varchar(100) DEFAULT NULL,
  `partner_surname` varchar(100) DEFAULT NULL,
  `partner_title` varchar(20) DEFAULT NULL,
  `partner_gender` varchar(10) DEFAULT NULL,
  `partner_id_number` varchar(20) DEFAULT NULL,
  `partner_id_type` varchar(30) DEFAULT NULL,
  `partner_id_issue_date` date DEFAULT NULL,
  `photo_path` varchar(255) DEFAULT NULL,
  `signature_path` varchar(255) DEFAULT NULL,
  `cor_certificate_uploaded` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Checkbox: COR 14.3 Certificate uploaded',
  `income_tax_notice_registration_uploaded` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Checkbox: SARS INCOME TAX - Notice of Registration',
  `payroll_notice_registration_uploaded` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Checkbox: Payroll Notice of Registration',
  `vat_registration_uploaded` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Checkbox: VAT Registration',
  `sars_representative_uploaded` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Checkbox: SARS Representative',
  `confirmation_of_banking_uplaoded` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Checkbox: Confirmation of Banking',
  `cor_14_3_certificate` varchar(100) DEFAULT NULL,
  `income_tax_registration` varchar(100) DEFAULT NULL,
  `payroll_registration` varchar(100) DEFAULT NULL,
  `vat_registration` varchar(100) DEFAULT NULL,
  `proof_of_bank_1` varchar(100) DEFAULT NULL,
  `proof_of_bank_2` varchar(100) DEFAULT NULL,
  `proof_of_bank_3` varchar(100) DEFAULT NULL,
  `take_on_signature` varchar(100) DEFAULT NULL,
  `sign_text` longtext DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `created_by` bigint(20) UNSIGNED DEFAULT NULL,
  `updated_by` bigint(20) UNSIGNED DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

