--
-- Table structure for table `client_master_banks`
--

CREATE TABLE `client_master_banks` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `client_id` bigint(20) UNSIGNED NOT NULL,
  `bank_id` bigint(20) UNSIGNED NOT NULL COMMENT 'FK to cims_bank_names.id',
  `document_id` int(11) DEFAULT NULL,
  `bank_name` varchar(255) DEFAULT NULL,
  `bank_account_holder` varchar(255) DEFAULT NULL,
  `bank_account_number` varchar(50) DEFAULT NULL,
  `bank_account_type_id` bigint(20) UNSIGNED DEFAULT NULL COMMENT 'FK to ref_bank_account_types.id',
  `bank_account_type_name` varchar(255) DEFAULT NULL,
  `bank_account_status_id` int(11) NOT NULL,
  `bank_account_status_name` varchar(50) DEFAULT NULL,
  `bank_statement_frequency_id` int(11) NOT NULL,
  `bank_statement_frequency_name` varchar(50) NOT NULL,
  `bank_statement_cut_off_date` date NOT NULL,
  `bank_branch_name` varchar(255) DEFAULT NULL,
  `bank_branch_code` varchar(50) DEFAULT NULL,
  `bank_swift_code` varchar(50) DEFAULT NULL,
