(4, 9, 'State Owned Company (SOC)', 'SOC', 'Company owned by the South African government. Provides essential services like electricity, water and transport. Subject to same legal requirements as other companies.', 'Government-owned entity providing public services', 1, NULL, NULL),
(5, 10, 'Public Company (Ltd)', 'Ltd', 'Large-scale business structure that can offer shares to the general public. Usually listed on stock exchanges. Requires minimum 3 directors and 7 shareholders.', 'Can offer shares publicly - for large businesses', 1, NULL, NULL),
(6, 11, 'Personal Liability Company (Inc)', 'Inc', 'Used by professionals like lawyers, doctors and accountants. Directors are jointly and severally liable for company debts incurred during their tenure.', 'Directors personally liable for debts - for professionals', 1, NULL, NULL),
(7, 21, 'Incorporated Company', 'Inc', 'A company incorporated under previous legislation. These entities continue to exist under the current Companies Act.', 'Company incorporated under previous legislation', 1, NULL, NULL),
(8, 23, 'Close Corporation (CC)', 'CC', 'No longer available for new registrations since 2011. Existing CCs remain valid. Similar to Pty but with members instead of shareholders. Maximum 10 natural person members.', 'Legacy structure - no new registrations since 2011', 1, NULL, NULL),
(9, 24, 'Co-operative', 'Co-op', 'An autonomous association of persons united to meet common economic, social, and cultural needs through a jointly-owned democratic enterprise.', 'Member-owned democratic enterprise', 1, NULL, NULL),
(10, 25, 'Primary Co-operative', 'Primary Co-op', 'A co-operative formed by natural persons to provide services directly to its members. First level of co-operative structure.', 'Direct member services co-operative', 1, NULL, NULL),
(11, 26, 'Secondary Co-operative', 'Secondary Co-op', 'A co-operative formed by two or more primary co-operatives to provide services to its member co-operatives.', 'Co-operative of primary co-operatives', 1, NULL, NULL);

