--
-- Table structure for table `share_types`
--

CREATE TABLE `share_types` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `name` varchar(255) NOT NULL,
  `tooltip` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Dumping data for table `share_types`
--

INSERT INTO `share_types` (`id`, `name`, `tooltip`, `created_at`, `updated_at`) VALUES
(1, 'Ordinary Shares', '<p><strong>This is the default and most common share type.</strong></p>\n<h4>Key Features</h4>\n<ul>\n  <li>Voting rights (usually 1 vote per share)</li>\n  <li>Right to dividends (if declared)</li>\n  <li>Right to share in assets on liquidation (last in line)</li>\n  <li>Used by most SMEs and private companies</li>\n</ul>\n<h4>Typical Use</h4>\n<ul>\n  <li>Founders</li>\n  <li>Active shareholders</li>\n  <li>B-BBEE ownership</li>\n</ul>', '2026-02-08 15:48:05', '2026-02-08 15:48:05'),
(2, 'Preference Shares', '<p><strong>These give priority over ordinary shares, usually financially.</strong></p>\n<h4>Key Features</h4>\n<ul>\n  <li>Preferential dividends (fixed or variable)</li>\n  <li>Paid before ordinary shares</li>\n  <li>Usually no voting rights (unless dividends not paid)</li>\n  <li>May be redeemable or convertible</li>\n</ul>\n<h4>Common Sub-types</h4>\n<ul>\n  <li>Cumulative preference shares</li>\n  <li>Non-cumulative preference shares</li>\n  <li>Redeemable preference shares</li>\n  <li>Convertible preference shares</li>\n</ul>\n<h4>Typical Use</h4>\n<ul>\n  <li>Investors</li>\n  <li>Funding structures</li>\n  <li>Shareholder loans converted to equity</li>\n</ul>', '2026-02-08 15:48:05', '2026-02-08 15:48:05'),
(3, 'Non-Voting Shares', '<p><strong>Shares with economic rights only, no votes.</strong></p>\n<h4>Key Features</h4>\n<ul>\n  <li>Entitled to dividends</li>\n  <li>No say in company decisions</li>\n  <li>Voting only in limited circumstances (e.g. class rights affected)</li>\n</ul>\n<h4>Typical Use</h4>\n<ul>\n  <li>Silent investors</li>\n  <li>Family businesses</li>\n  <li>B-BBEE structuring (carefully done)</li>\n</ul>', '2026-02-08 15:48:05', '2026-02-08 15:48:05'),
(4, 'Redeemable Shares', '<p><strong>Shares the company can buy back at a later date.</strong></p>\n<h4>Key Features</h4>\n<ul>\n  <li>Redemption date or trigger is defined</li>\n  <li>Often linked to funding agreements</li>\n  <li>Can be ordinary or preference shares</li>\n</ul>\n<h4>Typical Use</h4>\n<ul>\n  <li>Exit planning</li>\n  <li>Short-term investors</li>\n  <li>Structured finance deals</li>\n</ul>', '2026-02-08 15:48:05', '2026-02-08 15:48:05'),
(5, 'Convertible Shares', '<p><strong>Shares that can be converted into another class later.</strong></p>\n<h4>Key Features</h4>\n<ul>\n  <li>Usually convert into ordinary shares</li>\n  <li>Conversion ratio and timing defined upfront</li>\n  <li>Often used where valuation is deferred</li>\n</ul>\n<h4>Typical Use</h4>\n<ul>\n  <li>Angel investors</li>\n  <li>Venture funding</li>\n  <li>Growth-stage companies</li>\n</ul>', '2026-02-08 15:48:05', '2026-02-08 15:48:05'),
(6, 'Deferred Shares', '<p><strong>Shares with delayed rights.</strong></p>\n<h4>Key Features</h4>\n<ul>\n  <li>Dividends only after certain conditions</li>\n  <li>Often junior to ordinary shares</li>\n  <li>Rare, but allowed</li>\n</ul>\n<h4>Typical Use</h4>\n<ul>\n  <li>Employee incentive structures</li>\n  <li>Vendor earn-outs</li>\n</ul>', '2026-02-08 15:48:05', '2026-02-08 15:48:05'),
(7, 'Founder / Class Shares (A, B, C Shares)', '<p><strong>Custom share classes created in the MOI.</strong></p>\n<h4>Key Features</h4>\n<ul>\n  <li>Different voting rights per class</li>\n  <li>Different dividend rules</li>\n  <li>Different liquidation rights</li>\n</ul>\n<h4>Example</h4>\n<ul>\n  <li>Class A: 10 votes per share (founders)</li>\n  <li>Class B: 1 vote per share (investors)</li>\n  <li>Class C: no vote (employees)</li>\n</ul>\n<p><em>Very common in practice, especially where control is protected.</em></p>', '2026-02-08 15:48:05', '2026-02-08 15:48:05');

